import { Component, computed } from '@angular/core';
import { RouterOutlet, RouterLink, RouterLinkActive } from '@angular/router';
import { CommonModule } from '@angular/common';
import { AuthService } from './core/services/auth.service';
import { CartService } from './core/services/cart.service';

interface NavItem {
  label: string;
  path: string;
  icon: string;
  adminOnly?: boolean;
}

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [RouterOutlet, RouterLink, RouterLinkActive, CommonModule],
  templateUrl: './app.component.html',
  styleUrl: './app.component.css',
})
export class AppComponent {
  private readonly allNav: NavItem[] = [
    { label: 'Catalog', path: '/catalog', icon: '🛍️' },
    { label: 'Cart', path: '/cart', icon: '🛒' },
    { label: 'Orders', path: '/orders', icon: '📦' },
    { label: 'Products', path: '/admin/products', icon: '⚙️', adminOnly: true },
    { label: 'Sales', path: '/admin/orders', icon: '📊', adminOnly: true },
  ];

  readonly navItems = computed<NavItem[]>(() =>
    this.allNav.filter((item) => !item.adminOnly || this.auth.isAdmin()),
  );

  readonly isLoggedIn = this.auth.isLoggedIn;
  readonly isAdmin = this.auth.isAdmin;
  readonly user = this.auth.user;
  readonly cartCount = this.cart.count;

  constructor(
    private auth: AuthService,
    private cart: CartService,
  ) {}

  logout(): void {
    this.auth.logout();
  }
}
